// ─────────────────────────────────────────────
// Random Pings — mensagens espontâneas pra interatividade
// 40% de chance de pular cada grupo (independente)
// Mistura prompts genéricos com prompts contextuais
// ─────────────────────────────────────────────
const SKIP_CHANCE = 0.4;

const norm = (v) => String(v||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'');

const groupsResp = $('Fetch Active Groups').item.json;
const groupsList = Array.isArray(groupsResp) ? groupsResp : (groupsResp?.data || []);
const FALLBACK = [
  { wa_chat_id: '120363426390515923@g.us', label: 'Angel Fly', context_key: 'angelfly' },
  { wa_chat_id: '120363420996892188@g.us', label: 'Garlic',    context_key: 'garlic' },
  { wa_chat_id: '120363422948599063@g.us', label: 'Ernesto',   context_key: 'ernesto' }
];
const groups = groupsList.length ? groupsList : FALLBACK;

const collect = (items) => {
  const all = [];
  for (const it of items) {
    const j = it.json;
    if (Array.isArray(j)) j.forEach(r => r?.id && all.push(r));
    else if (Array.isArray(j?.data)) j.data.forEach(r => r?.id && all.push(r));
    else if (j?.id) all.push(j);
  }
  return all;
};
const tasks = collect($('Fetch All Tasks').all());

const today = new Date(Date.now() - 3*3600000).toISOString().slice(0,10);
const isOpen = (s) => !['done','closed','cancelled','resolved','completed'].includes(norm(s));
const groupMatch = (t, ctx) => {
  const blob = norm(t.project_name||'') + ' ' + norm(t.client_name||'');
  if (ctx==='garlic')   return /garlic|gnl|lemons/.test(blob);
  if (ctx==='ernesto')  return /ernesto|northend|north end|somerville|fax bridge|faxbridge/.test(blob);
  if (ctx==='angelfly') return /angel\s*fly|cockpit|jarvis/.test(blob);
  return true;
};

const hour = new Date(Date.now() - 3*3600000).getUTCHours();
const timeOfDay = hour < 12 ? 'morning' : (hour < 16 ? 'afternoon' : 'late');

// Prompts genéricos por horário
const PINGS_MORNING = [
  '☕ Bom dia! Como tá o pique da manhã? Algo novo pra registrar?',
  '👋 E aí, time! Café tomado? Posso ajudar a organizar algo?',
  'Manhã rolando. Se aparecer demanda nova, manda que eu registro 🚀',
  '🌤️ Bom dia! Algo pegando fogo ou tudo no flow?',
  'Bom diaaa. Tô aqui de plantão pra task/ticket/orçamento. Alguma coisa?'
];
const PINGS_AFTERNOON = [
  '👋 Como tá o dia? Alguma novidade que vale virar task?',
  'Status check rápido: tudo flowing? Bloqueio pra reportar?',
  '🌞 Meio do dia — algum bug aparecendo ou tudo de boa?',
  'Pausa pro almoço logo? Antes disso, alguma demanda nova?',
  'Hora do check-in! Se tem algo na cabeça que vale anotar, é agora 👀',
  'PM mode: ritmo OK? Se algo precisa registrar, manda ver.'
];
const PINGS_LATE = [
  '🌅 Reta final do dia. Algo que ficou pra registrar antes de fechar?',
  'Final de tarde — última chance pra criar task antes do café da manhã 😅',
  'Dia tá indo bem? Algo novo apareceu no fim da tarde?',
  '☕ Café da tarde + status update? Conta aí o que tá rolando.',
  'Encerrando o dia logo. Bug, demanda, atualização — qualquer coisa, manda.',
  '👀 Olhando o cockpit aqui... alguém quer dar update no que tá In Progress?'
];

// Prompts contextuais (mais inteligentes — só usa se tiver dados)
function contextualPrompt(ctx, label) {
  const groupTasks = tasks.filter(t => isOpen(t.status) && groupMatch(t, ctx));
  const overdue = groupTasks.filter(t => t.deadline && t.deadline.slice(0,10) < today);
  const backlog = groupTasks.filter(t => norm(t.status) === 'backlog');
  const inProgress = groupTasks.filter(t => norm(t.status) === 'in_progress' || norm(t.status) === 'assigned');
  const noOwner = groupTasks.filter(t => !t.assigned_to_name);

  const options = [];
  if (overdue.length >= 2) {
    options.push(`👀 Tem ${overdue.length} tasks atrasadas no ${label}. Quer que eu chame nominalmente quem tá com cada uma?`);
  }
  if (backlog.length >= 3) {
    options.push(`📋 Backlog do ${label} tem ${backlog.length} tasks paradas. Bora distribuir alguma hoje?`);
  }
  if (inProgress.length >= 1) {
    const t = inProgress[Math.floor(Math.random() * inProgress.length)];
    const who = t.assigned_to_name ? t.assigned_to_name : 'galera';
    options.push(`Olha só, '${t.title}' tá In Progress há um tempo. Tudo correndo, ${who}?`);
  }
  if (noOwner.length >= 2) {
    options.push(`🔍 Tem ${noOwner.length} tasks sem dono no ${label}. Quem pega?`);
  }
  return options.length ? options[Math.floor(Math.random() * options.length)] : null;
}

function pickGenericPrompt() {
  const pool = timeOfDay === 'morning' ? PINGS_MORNING : (timeOfDay === 'afternoon' ? PINGS_AFTERNOON : PINGS_LATE);
  return pool[Math.floor(Math.random() * pool.length)];
}

const results = [];
for (const g of groups) {
  // Independent skip dice for each group
  if (Math.random() < SKIP_CHANCE) continue;

  const ctx = g.context_key || g.context;
  const label = g.label || ctx;

  // 40% chance: try contextual prompt (if data supports it)
  // 60% chance: generic prompt
  let msg = null;
  if (Math.random() < 0.4) {
    msg = contextualPrompt(ctx, label);
  }
  if (!msg) {
    msg = pickGenericPrompt();
  }

  results.push({ json: { number: g.wa_chat_id, text: msg, label } });
}

if (!results.length) return [{ json: { skip: true, reason: 'all_groups_skipped_or_no_groups' } }];

return results;
